proof fn phi_1_always_implies_to_leads_to_intensional_bridge(spec: TempPred<int>, p: TempPred<int>, q: TempPred<int>)
    requires
        spec.entails(always(p.implies(q))),
    ensures
        spec.entails(p.leads_to(q)),
{
    always_implies_to_leads_to::<int>(spec, p, q);
}

proof fn phi_2_leads_to_trans_intensional_bridge(spec: TempPred<int>, p: TempPred<int>, q: TempPred<int>, r: TempPred<int>)
    requires
        spec.entails(p.leads_to(q)),
        spec.entails(q.leads_to(r)),
    ensures
        spec.entails(p.leads_to(r)),
{
    leads_to_trans::<int>(spec, p, q, r);
}

proof fn phi_3_implication_strengthens_to_leads_to(spec: TempPred<int>, p: TempPred<int>)
    requires
        spec.entails(always(p.implies(p))),
    ensures
        spec.entails(p.leads_to(p)),
{
    always_implies_to_leads_to::<int>(spec, p, p);
}

proof fn phi_4_false_spec_any_leads_to(p: TempPred<int>, q: TempPred<int>)
    requires
        TempPred::<int>::new(|ex: Execution<int>| false).entails(always(p.implies(q))),
    ensures
        TempPred::<int>::new(|ex: Execution<int>| false).entails(p.leads_to(q)),
{
    always_implies_to_leads_to::<int>(TempPred::new(|ex: Execution<int>| false), p, q);
}

proof fn phi_5_weaken_to_trivial(spec: TempPred<int>, p: TempPred<int>, q: TempPred<int>)
    requires
        spec.entails(always(p.implies(p))),
        spec.entails(always(q.implies(q))),
        spec.entails(p.leads_to(q)),
    ensures
        spec.entails(p.leads_to(q)),
{
    leads_to_weaken::<int>(spec, p, q, p, q);
}
